(()=>{document.addEventListener("DOMContentLoaded",()=>{let n=document.getElementById("burgerBtn"),t=document.getElementById("sidebar"),s=document.getElementById("overlay"),i=document.getElementById("closeBtn");if(!n||!t||!s)return;function o(){t.classList.contains("open")?(t.classList.remove("open"),s.classList.remove("visible"),n.classList.remove("open")):(t.classList.add("open"),s.classList.add("visible"),n.classList.add("open"))}n.addEventListener("click",e=>{e.stopPropagation(),o()}),i&&i.addEventListener("click",e=>{e.stopPropagation(),o()}),s.addEventListener("click",o),document.addEventListener("keydown",e=>{e.key==="Escape"&&t.classList.contains("open")&&o()})});})();
